SELECT count(*) FROM company_type, movie_companies, title, kind_type, cast_info, movie_keyword, role_type, keyword, movie_info WHERE movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_keyword.keyword_id = keyword.id AND movie_info.movie_id = title.id;